        switch self {
        case .keyNotFound: return "Key not found."
        case .keyGenerationFailed: return "Key generation failed."
        case .keyExportNotAllowed: return "Key export not allowed."
        case .keyImportFailed: return "Key import failed."
        case .signingFailed: return "Signing failed."
        case .invalidHex: return "Invalid hex."
        case .invalidURL: return "Invalid URL."
        case .networkError(let s): return "Network error: \(s)"
        case .rpcError(let s): return "RPC error: \(s)"
        case .invalidResponse: return "Invalid response."
        }
    }
}

// MARK: - Utilities

extension Data {
    init(hex: String) throws {
        let s = hex.lowercased().hasPrefix("0x") ? String(hex.dropFirst(2)) : hex
        guard s.count % 2 == 0 else { throw WalletError.invalidHex }
        var data = Data()
        data.reserveCapacity(s.count / 2)
        var idx = s.startIndex
        while idx < s.endIndex {
            let next = s.index(idx, offsetBy: 2)
            let byteStr = s[idx..<next]
            guard let b = UInt8(byteStr, radix: 16) else { throw WalletError.invalidHex }
            data.append(b)
            idx = next
        }
        self = data
    }

    func hexString(prefix: Bool = true) -> String {
        let hex = self.map { String(format: "%02x", $0) }.joined()
        return prefix ? "0x" + hex : hex
    }
}

extension String {
    func trimmed() -> String { trimmingCharacters(in: .whitespacesAndNewlines) }
}

// MARK: - Keystore (Secure Enclave / Keychain)

final class KeyStore {
    static let shared = KeyStore()

    private let tag = "com.example.wallet.secp256k1.key".data(using: .utf8)!
    private let accessControl: SecAccessControl = {
        SecAccessControlCreateWithFlags(nil,
                                       kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                                       [.privateKeyUsage, .biometryAny],
                                       nil)!
    }()

    private init() {}

    func generateKeyIfNeeded() throws {
        if try loadPrivateKey() != nil { return }

        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecAttrTokenID as String: kSecAttrTokenIDSecureEnclave,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: tag,
                kSecAttrAccessControl as String: accessControl
            ]
        ]

        var error: Unmanaged<CFError>?
        guard SecKeyCreateRandomKey(attributes as CFDictionary, &error) != nil else {
            throw WalletError.keyGenerationFailed
        }
    }

    func loadPrivateKey() throws -> SecKey? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecReturnRef as String: true
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        if status == errSecItemNotFound { return nil }
        guard status == errSecSuccess else { throw WalletError.keyNotFound }
        return (item as! SecKey)
    }

    func deleteKey() throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom
        ]
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw WalletError.keyNotFound
        }
    }

    func publicKeyData() throws -> Data {
        guard let priv = try loadPrivateKey() else { throw WalletError.keyNotFound }
        guard let pub = SecKeyCopyPublicKey(priv) else { throw WalletError.keyNotFound }
        var error: Unmanaged<CFError>?
        guard let data = SecKeyCopyExternalRepresentation(pub, &error) as Data? else {
            throw WalletError.keyNotFound
        }
        return data
    }

    func sign(hash32: Data) throws -> Data {
        guard hash32.count == 32 else { throw WalletError.signingFailed }
        guard let priv = try loadPrivateKey() else { throw WalletError.keyNotFound }

        let algorithm = SecKeyAlgorithm.ecdsaSignatureDigestX962SHA256
        guard SecKeyIsAlgorithmSupported(priv, .sign, algorithm) else { throw WalletError.signingFailed }

        var error: Unmanaged<CFError>?
        guard let sig = SecKeyCreateSignature(priv, algorithm, hash32 as CFData, &error) as Data? else {
            throw WalletError.signingFailed
        }
        return sig
    }
}

// MARK: - Simple Ethereum-like Transaction (EIP-1559 minimal)

struct EthTransaction: Codable {
    var chainId: UInt64
    var nonce: UInt64
    var maxPriorityFeePerGas: UInt64
    var maxFeePerGas: UInt64
    var gasLimit: UInt64
    var to: String
    var valueWei: UInt64
    var dataHex: String

    func canonicalMessage() throws -> Data {
        let dict: [String: Any] = [
            "chainId": chainId,
            "nonce": nonce,
            "maxPriorityFeePerGas": maxPriorityFeePerGas,
            "maxFeePerGas": maxFeePerGas,
            "gasLimit": gasLimit,
            "to": to.lowercased(),
            "valueWei": valueWei,
            "data": dataHex.lowercased()
        ]
        let json = try JSONSerialization.data(withJSONObject: dict, options: [.sortedKeys])
        return json
    }

    func hashForSigning() throws -> Data {
        let msg = try canonicalMessage()
        let digest = SHA256.hash(data: msg)
        return Data(digest)
    }
}

struct SignedTransaction: Codable {
    var tx: EthTransaction
    var publicKeyHex: String
    var signatureDerHex: String
    var messageHashHex: String
}

// MARK: - JSON-RPC Client (Ethereum)

final class EthereumRPC {
    let url: URL
    private let session: URLSession

    init(endpoint: String) throws {
        guard let u = URL(string: endpoint) else { throw WalletError.invalidURL }
        self.url = u
        self.session = URLSession(configuration: .default)
    }

    struct RPCRequest: Encodable {
        let jsonrpc: String = "2.0"
        let id: Int
        let method: String
        let params: [AnyEncodable]
    }

    struct RPCResponse<T: Decodable>: Decodable {
        let jsonrpc: String?
        let id: Int?
        let result: T?
        let error: RPCError?
    }

    struct RPCError: Decodable {
        let code: Int?
        let message: String?
        let data: String?
    }

    func call<T: Decodable>(_ method: String, _ params: [AnyEncodable], result: T.Type) async throws -> T {
        let req = RPCRequest(id: Int.random(in: 1...1_000_000), method: method, params: params)
        let body = try JSONEncoder().encode(req)

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = body

        let (data, resp) = try await session.data(for: request)
        guard let http = resp as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw WalletError.networkError("HTTP error")
        }

        let decoded = try JSONDecoder().decode(RPCResponse<T>.self, from: data)
        if let err = decoded.error {
            throw WalletError.rpcError(err.message ?? "Unknown RPC error")
        }
        guard let res = decoded.result else { throw WalletError.invalidResponse }
        return res
    }

    func ethChainId() async throws -> String {
        try await call("eth_chainId", [], result: String.self)
    }

    func ethGetTransactionCount(address: String, tag: String = "latest") async throws -> String {
        try await call("eth_getTransactionCount", [AnyEncodable(address), AnyEncodable(tag)], result: String.self)
    }

    func ethSendRawTransaction(raw: String) async throws -> String {
        try await call("eth_sendRawTransaction", [AnyEncodable(raw)], result: String.self)
    }
}

// MARK: - AnyEncodable

struct AnyEncodable: Encodable {
    private let encodeFunc: (Encoder) throws -> Void

    init<T: Encodable>(_ value: T) {
        self.encodeFunc = value.encode
    }

    func encode(to encoder: Encoder) throws {
        try encodeFunc(encoder)
    }
}

// MARK: - Wallet Service

final class WalletService {
    static let shared = WalletService()

    private init() {}

    func ensureKey() throws {
        try KeyStore.shared.generateKeyIfNeeded()
    }

    func publicKeyHex() throws -> String {
        let pub = try KeyStore.shared.publicKeyData()
        return pub.hexString()
    }

    func signTransaction(_ tx: EthTransaction) throws -> SignedTransaction {
        let hash = try tx.hashForSigning()
        let sig = try KeyStore.shared.sign(hash32: hash)
        let pub = try KeyStore.shared.publicKeyData()
        return SignedTransaction(
            tx: tx,
            publicKeyHex: pub.hexString(),
            signatureDerHex: sig.hexString(),
            messageHashHex: hash.hexString()
        )
    }

    func exportSignedPayload(_ signed: SignedTransaction) throws -> String {
        let data = try JSONEncoder().encode(signed)
        return String(data: data, encoding: .utf8) ?? ""
    }
}

